package de.hdawg.tennis.rankinginfo.controller;import de.hdawg.tennis.rankinginfo.model.Ranking;import de.hdawg.tennis.rankinginfo.repository.RankingRepository;import lombok.RequiredArgsConstructor;import lombok.extern.slf4j.Slf4j;import org.springframework.stereotype.Controller;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.GetMapping;import org.springframework.web.bind.annotation.RequestParam;import java.time.LocalDate;import java.util.List;@Slf4j@RequiredArgsConstructor@Controllerpublic class RankingController {    private final RankingRepository rankingRepository;    @GetMapping("/listings")    public String getRankingList(@RequestParam(name = "quarter", required = false) String period, @RequestParam(name = "gender", required = false) String gender, @RequestParam(name = "age_group", required = false) String ageGroup, @RequestParam(name = "age_group_options", required = false) String ageGroupOptions, @RequestParam(name = "federation", required = false) String federation, @RequestParam(name = "club", required = false) String club, @RequestParam(name = "commit", required = false) String commited, Model model) {        List<Ranking> rankings = rankingRepository.retrieveRankingListItems(LocalDate.now(), false, false, "U14c", null, "BVH Tennis");        model.addAttribute(rankings);        return "listing";    }}